const helmet  = require('helmet');
const cors    = require('cors');
const morgan  = require('morgan');
const rateLimit = require('express-rate-limit');

const app = express();

// ── Security headers ────────────────────────────────────────────────────────
app.disable('x-powered-by');
app.use(helmet());
app.use(cors({
  origin: (process.env.ALLOWED_ORIGINS || '').split(','),
  methods: ['GET'],
}));

// ── Body parsing with size limit ────────────────────────────────────────────
app.use(express.json({ limit: '10kb' }));

// ── Logging ─────────────────────────────────────────────────────────────────
app.use(morgan('combined'));

// ── Rate limiting ────────────────────────────────────────────────────────────
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }));

// ── Authentication middleware ────────────────────────────────────────────────
const authenticate = (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1];
  const user  = token && verifyToken(token);    // implement verifyToken()
  if (!user) return res.status(401).json({ error: 'Unauthorized' });
  req.user = user;
  next();
};

// ── Routes ───────────────────────────────────────────────────────────────────
app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });                   // removed timestamp
});

app.get('/users', authenticate, (req, res) => {
  // fetch from DB using parameterized queries
  res.json(getUsersFromDb());
});

// ── 404 handler ──────────────────────────────────────────────────────────────
app.use((_req, res) => res.status(404).json({ error: 'Not found' }));

// ── Global error handler ─────────────────────────────────────────────────────
app.use((err, _req, res, _next) => {
  console.error(err);                           // replace with winston in prod
  res.status(500).json({ error: 'Internal server error' });
});

// ── Startup ──────────────────────────────────────────────────────────────────
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () =>
  console.log(`Server running on port ${PORT}`)
);

// ── Graceful shutdown ────────────────────────────────────────────────────────
const shutdown = () => server.close(() => process.exit(0));
process.on('SIGTERM', shutdown);
process.on('SIGINT',  shutdown);

module.exports = app;
```

